import React, { useState } from 'react';
import './AdminLogin.css';

const AdminLogin = ({ onLogin }) => {
  const [formData, setFormData] = useState({
    username: '',
    password: ''
  });
  const [errors, setErrors] = useState({});
  const [isLoading, setIsLoading] = useState(false);

  const validateForm = () => {
    const newErrors = {};

    if (!formData.username.trim()) {
      newErrors.username = 'Username or Email is required';
    }

    if (!formData.password.trim()) {
      newErrors.password = 'Password is required';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    setIsLoading(true);
    setErrors({});

    try {
      // Simulate authentication - in real app, this would be an API call
      const response = await mockAdminAuth(formData);

      if (response.success) {
        onLogin(response.user);
      } else {
        setErrors({ general: response.message || 'Invalid credentials' });
      }
    } catch (error) {
      setErrors({ general: 'Authentication failed. Please try again.' });
    } finally {
      setIsLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));

    // Clear error for this field when user starts typing
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
  };

  return (
    <div className="admin-login-container">
      <div className="admin-login-card">
        <div className="login-header">
          <div className="login-icon">🔐</div>
          <div className="login-title">
            <h1>Admin Login</h1>
            <p>🏥 Patient Readmission Predictor</p>
            <div className="login-subtitle">AI-Powered Risk Assessment for Hospital Readmission</div>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="login-form">
          {errors.general && (
            <div className="error-message">
              <div className="error-icon">⚠️</div>
              <div className="error-content">
                <h2>Access Denied</h2>
                <p>{errors.general}</p>
                <p>Please check your credentials and try again.</p>
              </div>
            </div>
          )}

          <div className="form-group">
            <label htmlFor="username">
              <span className="input-icon">👤</span>
              Username or Email
            </label>
            <input
              type="text"
              id="username"
              name="username"
              value={formData.username}
              onChange={handleChange}
              placeholder="Enter username or email"
              className={errors.username ? 'error' : ''}
              disabled={isLoading}
            />
            {errors.username && (
              <span className="error-text">{errors.username}</span>
            )}
          </div>

          <div className="form-group">
            <label htmlFor="password">
              <span className="input-icon">🔒</span>
              Password
            </label>
            <input
              type="password"
              id="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              placeholder="Enter password"
              className={errors.password ? 'error' : ''}
              disabled={isLoading}
            />
            {errors.password && (
              <span className="error-text">{errors.password}</span>
            )}
          </div>

          <button type="submit" className="login-btn" disabled={isLoading}>
            {isLoading ? (
              <>
                <div className="spinner"></div>
                Authenticating...
              </>
            ) : (
              <>
                <span className="login-btn-text">Sign In</span>
                <span className="login-btn-icon">→</span>
              </>
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

// Mock authentication function - replace with real API call
const mockAdminAuth = async (credentials) => {
  // Simulate API delay
  await new Promise(resolve => setTimeout(resolve, 1000));

  // Mock admin credentials - replace with real authentication
  const ADMIN_CREDENTIALS = {
    'username-admin': 'username-admin',
    'password-admin': 'passowrs-admin',
    'doctor': 'doctor',
    'nurse': 'nurse'
  };

  const isValid = ADMIN_CREDENTIALS[credentials.username] && 
                   ADMIN_CREDENTIALS[credentials.username] === credentials.password;

  if (isValid) {
    return {
      success: true,
      user: {
        username: credentials.username,
        role: 'admin',
        name: 'Administrator'
      }
    };
  } else {
    return {
      success: false,
      message: 'Invalid credentials'
    };
  }
};

export default AdminLogin;
